// Helper function to get prime factors of a number V using SPF array
// Assumes V >= 1. If V=1, returns empty list.
fun getPrimeFactors(v: Long, spf: IntArray): List<Long> {
    if (v <= 1) return emptyList()
    val factors = mutableSetOf<Long>()
    var current = v.toInt()
    while (current > 1) {
        val p = spf[current]
        factors.add(p.toLong())
        while (current % p == 0) {
            current /= p
        }
    }
    return factors.toList()
}

